def _call(f, args):
    if isinstance(f, UserFunction):
        call_env = Environment(parent=f.closure_env)
        for param, arg in zip(f.params, args):
            call_env.set(param, arg)
        try:
            self._eval_body(f.body, call_env)
            return None
        except ReturnSignal as ret:
            return ret.value
    return f(*args)

self.global_env.set("map", lambda f, x: [_call(f, [item]) for item in x])
self.global_env.set("filter", lambda f, x: [item for item in x if _call(f, [item])])

